        blockHeight: bigint;
        depositDetails: CfChainsEvmDepositDetails;
        ingressFee: bigint;
        maxBoostFeeBps: number;
        action: PalletCfIngressEgressDepositAction;
        channelId?: bigint | undefined;
        originType: CfChainsDepositOriginType;
